#include <bits/stdc++.h>
using namespace std;
int n,w;
long long c[100005];
int Lowbit(int a){
    int cnt=0;
    while(!(a&1))
        a>>=1,cnt++;
    return 1<<cnt;
}
void Plus(int a,int b){
    if(a>n)
        return;
    c[a]+=b;
    Plus(a+Lowbit(a),b);
}
long long Sum(int a){
    if(!a)
        return 0;
    else
        return c[a]+Sum(a-Lowbit(a));
}
int main(){
    cin>>n>>w;
    while(w--){
        char op;
        int a,b;
        cin>>op>>a>>b;
        if(op=='x')
            Plus(a,b);
        else
            cout<<Sum(b)-Sum(a-1)<<endl;
    }
    return 0;
}
